  async search(query, options = {}) {
    const startTime = Date.now();
    const cacheKey = `search:${query}:${JSON.stringify(options)}`;

    // 缓存查询（1小时）
    if (this.cache && this.cache.has(cacheKey)) {
      const cached = this.cache.get(cacheKey);
      if (Date.now() - cached.timestamp < 3600000) {
        this.trace(query, 'CACHE HIT');
        return cached.result;
      }
    }

    let lastError = null;
    for (const source of this.fallbackChain) {
      try {
        this.trace(query, `Trying ${source.name}...`);
        const result = await source.search(query, options);
        if (result && result.length > 0) {
          this.trace(query, `✓ ${source.name} returned ${result.length} results`);

          if (this.cache) {
            this.cache.set(cacheKey, { result, timestamp: Date.now() });
          }

          return {
            results,
            source: source.name,
            query,
            timestamp: new Date().toISOString(),
            latency: Date.now() - startTime
          };
        }
      } catch (err) {
        lastError = err;
        this.trace(query, `✗ ${source.name}: ${err.message}`);
      }
    }

    return {
      results: [],
      source: 'none',
      error: lastError?.message || 'All sources failed',
      query,
      timestamp: new Date().toISOString(),
      latency: Date.now() - startTime
    };
  }
}

class WikipediaSource {
  name = 'Wikipedia';

  async search(query, options = {}) {
    const lang = options.lang || 'en';
    const limit = options.limit || 10;

    const url = `https://${lang}.wikipedia.org/w/api.php?` + new URLSearchParams({
      action: 'query',
      list: 'search',
      srsearch: query,
      format: 'json',
      limit,
      origin: '*'
    });

    const res = await fetch(url);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);

    const data = await res.json();
    return data.query.search.map(item => ({
      title: item.title,
      url: `https://${lang}.wikipedia.org/wiki/${encodeURIComponent(item.title.replace(/ /g, '_'))}`,
      snippet: item.snippet.replace(/<[^>]+>/g, ''),
      source: 'wikipedia'
    }));
  }
}

class ArxivSource {
  name = 'ArXiv';

  async search(query, options = {}) {
    const maxResults = options.limit || 10;
    const url = `https://export.arxiv.org/api/query?` + new URLSearchParams({
      searchQuery: `all:${query}`,
      max_results: maxResults,
      sortBy: 'relevance',
      sortOrder: 'descending'
    });

    const res = await fetch(url);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);

    const text = await res.text();
    const entries = text.match(/<entry>([\s\S]*?)<\/entry>/g) || [];

    return entries.map(entry => {
      const getTag = (tag) => {
        const m = entry.match(new RegExp(`<${tag}[^>]*>([\s\S]*?)</${tag}>`));
        return m ? m[1].trim() : '';
      };
      return {
        title: getTag('title').replace(/\n/g, ' '),
        url: getTag('id'),
        snippet: getTag('summary').slice(0, 200) + '...',
        source: 'arxiv',
        authors: getTag('name')
      };
    });
  }
}

class GitHubSource {
  name = 'GitHub';

  async search(query, options = {}) {
    const limit = options.limit || 10;
    const url = `https://api.github.com/search/repositories?` + new URLSearchParams({
      q: query,
      per_page: limit,
      sort: 'stars',
      order: 'desc'
    });

    const res = await fetch(url, {
      headers: {
        'Accept': 'application/vnd.github.v3+json',
        'User-Agent': 'HermesSearchFramework/1.0'
      }
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);

    const data = await res.json();
    return data.items.map(repo => ({
      title: repo.full_name,
      url: repo.html_url,
      snippet: `${repo.description || 'No description'} | ⭐ ${repo.stargazers_count} | ${repo.language || 'N/A'}`,
      source: 'github',
      stars: repo.stargazers_count
    }));
  }
}

